mapper.select:
SELECT id, code, created_at, used_by, used_at, is_active, sent_user_name, sent_email, last_sent_at
FROM invitation_code
WHERE id = #{id}

SELECT id, code, created_at, used_by, used_at, is_active, sent_user_name, sent_email, last_sent_at
FROM invitation_code
WHERE id >= (
    SELECT id
    FROM invitation_code
    ORDER BY created_at DESC
    LIMIT 1 OFFSET #{offset}
)
ORDER BY created_at DESC
LIMIT #{size}

SELECT id, code, created_at, used_by, used_at, is_active, sent_user_name, sent_email, last_sent_at
FROM invitation_code
WHERE code = #{code}

SELECT id, code, created_at, used_by, used_at, is_active, sent_user_name, sent_email, last_sent_at
FROM invitation_code
WHERE used_by = #{usedBy}

mapper.update:
UPDATE invitation_code
used_by = #{usedBy}, used_at = #{usedAt}, is_active = #{isActive}, sent_user_name = #{sentUserName}, sent_email = #{sentEmail}, last_sent_at = #{lastSentAt},
WHERE id = #{id}
